import { useState } from 'react';
import { useCharStore } from '../../store/charStore';
import type { ICharacterAdvantage } from '../../entities/types';
import advantageDefsRaw from '../../data/advantages.json';
import { useLocalizedData } from '../../shared/hooks/useLocalizedData';
import { Tooltip } from '../../shared/ui/Tooltip';
import { Plus, Trash2 } from 'lucide-react';
import { useTranslation } from 'react-i18next';

export function AdvantagesPanel({ cost }: { cost: number }) {
  const { t } = useTranslation();
  const advantageDefs = useLocalizedData(advantageDefsRaw as any) as typeof advantageDefsRaw;
  const advantages = useCharStore((s) => s.character.advantages);
  const [showAdd, setShowAdd] = useState(false);
  const [newAdvId, setNewAdvId] = useState('');

  function setAdvantages(next: ICharacterAdvantage[]) {
    useCharStore.setState((s) => ({
      character: { ...s.character, advantages: next },
      isDirty: true,
    }));
  }

  function addAdvantage() {
    if (!newAdvId) return;
    // If already exists and it's ranked, just bump rank
    const existing = advantages.findIndex((a) => a.advantageId === newAdvId);
    const def = advantageDefs.find((d) => d.id === newAdvId);
    if (!def) return;

    if (existing >= 0 && def.ranked) {
      const next = [...advantages];
      next[existing] = { ...next[existing], ranks: next[existing].ranks + 1 };
      setAdvantages(next);
    } else if (existing < 0) {
      setAdvantages([...advantages, { advantageId: newAdvId, ranks: 1 }]);
    }
    setNewAdvId('');
    setShowAdd(false);
  }

  function updateRanks(index: number, ranks: number) {
    const next = [...advantages];
    next[index] = { ...next[index], ranks: Math.max(1, ranks) };
    setAdvantages(next);
  }

  function removeAdvantage(index: number) {
    setAdvantages(advantages.filter((_, i) => i !== index));
  }

  const availableToAdd = advantageDefs.filter((def) => {
    if (def.ranked) return true;
    return !advantages.some((a) => a.advantageId === def.id);
  });

  return (
    <section className="panel">
      <div className="panel-header">
        <h2 className="panel-title">{t('advantages.title')}</h2>
        <span className="panel-cost">{cost} {t('common.pp')}</span>
      </div>

      {advantages.length === 0 && (
        <p className="adv-empty">{t('advantages.noAdvantages')}</p>
      )}

      <div className="adv-grid">
        {advantages.map((adv, i) => {
          const def = advantageDefs.find((d) => d.id === adv.advantageId);
          if (!def) return null;
          return (
            <div key={`${adv.advantageId}-${i}`} className="adv-chip">
              <Tooltip content={def.description!}>
                <span className="adv-name">{def.name}</span>
              </Tooltip>
              {def.ranked && (
                <input
                  type="number" min={1}
                  className="adv-rank-input"
                  value={adv.ranks}
                  onChange={(e) => updateRanks(i, Number(e.target.value) || 1)}
                />
              )}
              <button className="adv-remove" onClick={() => removeAdvantage(i)} title={t('common.remove')}>
                <Trash2 size={12} />
              </button>
            </div>
          );
        })}
      </div>

      {!showAdd ? (
        <button className="skill-add-btn" onClick={() => setShowAdd(true)}>
          <Plus size={16} /> {t('advantages.addAdvantage')}
        </button>
      ) : (
        <div className="skill-add-form">
          <select value={newAdvId} onChange={(e) => setNewAdvId(e.target.value)} className="skill-select">
            <option value="">{t('common.select')}</option>
            {availableToAdd.map((d) => (
              <option key={d.id} value={d.id}>{d.name}{d.ranked ? ` (${t('common.rank')})` : ''}</option>
            ))}
          </select>
          <button className="skill-confirm-btn" onClick={addAdvantage} disabled={!newAdvId}>
            {t('common.add')}
          </button>
          <button className="skill-cancel-btn" onClick={() => { setShowAdd(false); setNewAdvId(''); }}>
            {t('common.cancel')}
          </button>
        </div>
      )}

      <style>{`
        .adv-empty { color: var(--c-text-muted); font-size: 0.85rem; font-style: italic; }
        .adv-grid { display: flex; flex-wrap: wrap; gap: var(--s-sm); }
        .adv-chip {
          display: flex; align-items: center; gap: var(--s-xs);
          background: var(--c-surface-elevated); border: 1px solid var(--c-border);
          border-radius: var(--r-full); padding: var(--s-xs) var(--s-md);
          transition: border-color var(--t-fast);
        }
        .adv-chip:hover { border-color: var(--c-border-active); }
        .adv-name { font-size: 0.82rem; font-weight: 500; cursor: help; white-space: nowrap; }
        .adv-rank-input {
          width: 36px; text-align: center;
          background: var(--c-bg); border: 1px solid var(--c-border);
          border-radius: var(--r-sm); color: var(--c-primary);
          font-family: var(--f-body); font-size: 0.8rem; font-weight: 700;
          padding: 2px;
        }
        .adv-rank-input:focus { outline: none; border-color: var(--c-primary); }
        .adv-remove {
          background: transparent; border: none; color: var(--c-text-muted);
          cursor: pointer; opacity: 0; transition: opacity var(--t-fast), color var(--t-fast);
          display: flex; padding: 2px;
        }
        .adv-chip:hover .adv-remove { opacity: 1; }
        .adv-remove:hover { color: var(--c-error); }
      `}</style>
    </section>
  );
}

import { useState } from 'react';
import { useCharStore } from '../../store/charStore';
import type { ICharacterPower } from '../../entities/types';
import powerDefsRaw from '../../data/powers.json';
import modifierDefsRaw from '../../data/modifiers.json';
import { useLocalizedData } from '../../shared/hooks/useLocalizedData';
import { calculatePowerCost, calculateArrayCost } from '../../shared/lib/mathEngine';
import { PowerBuilderOverlay } from '../power-builder/PowerBuilderOverlay';
import { Tooltip } from '../../shared/ui/Tooltip';
import { Plus, Edit3, Trash2, Zap } from 'lucide-react';
import { useTranslation } from 'react-i18next';

export function PowersList({ cost: _cost }: { cost: number }) {
  const { t } = useTranslation();
  const powerDefs = useLocalizedData(powerDefsRaw as any) as typeof powerDefsRaw;
  const modifierDefs = useLocalizedData(modifierDefsRaw as any) as typeof modifierDefsRaw;

  const powers = useCharStore((s) => s.character.powers);
  const [builderOpen, setBuilderOpen] = useState(false);
  const [editIndex, setEditIndex] = useState<number | null>(null);

  function setPowers(next: ICharacterPower[]) {
    useCharStore.setState((s) => ({
      character: { ...s.character, powers: next },
      isDirty: true,
    }));
  }

  function handleSavePower(power: ICharacterPower) {
    if (editIndex !== null) {
      const next = [...powers];
      next[editIndex] = power;
      setPowers(next);
    } else {
      setPowers([...powers, power]);
    }
    setBuilderOpen(false);
    setEditIndex(null);
  }

  function handleDeletePower(index: number) {
    const power = powers[index];
    const altCount = power.alternateEffects.length;
    let msg = altCount > 0
      ? t('powers.deleteConfirmWithAlt', { name: power.name, count: altCount })
      : t('powers.deleteConfirm', { name: power.name });

    // Default messages if translation is missing placeholders or hasn't loaded properly in the test
    if (msg === 'powers.deleteConfirmWithAlt' || msg === 'powers.deleteConfirm') {
       msg = altCount > 0 ? `Excluir "${power.name}" e seus ${altCount} Efeito(s) Alternativo(s)?` : `Excluir "${power.name}"?`;
    }

    if (confirm(msg)) {
      setPowers(powers.filter((_, i) => i !== index));
    }
  }

  function openNew() {
    setEditIndex(null);
    setBuilderOpen(true);
  }

  function openEdit(index: number) {
    setEditIndex(index);
    setBuilderOpen(true);
  }

  // Calculate total power cost
  const totalPowersCost = powers.reduce((sum, p) => {
    const def = powerDefs.find((d) => d.id === p.effectId);
    const baseCost = def?.baseCost ?? 1;
    const mainCost = calculatePowerCost(baseCost, p.ranks, p.modifiers, modifierDefs as any);
    const dynamicCount = p.alternateEffects.filter((a) => a.dynamic).length;
    return sum + calculateArrayCost(mainCost, p.alternateEffects.length, dynamicCount);
  }, 0);

  return (
    <section className="panel">
      <div className="panel-header">
        <h2 className="panel-title">{t('powers.title')}</h2>
        <span className="panel-cost">{totalPowersCost} {t('common.pp')}</span>
      </div>

      {powers.length === 0 && (
        <p className="power-empty">{t('powers.noPowers')}</p>
      )}

      <div className="powers-grid">
        {powers.map((power, i) => {
          const effectDef = powerDefs.find((d) => d.id === power.effectId);
          const baseCost = effectDef?.baseCost ?? 1;
          const mainCost = calculatePowerCost(baseCost, power.ranks, power.modifiers, modifierDefs as any);
          const dynamicCount = power.alternateEffects.filter((a) => a.dynamic).length;
          const totalCost = calculateArrayCost(mainCost, power.alternateEffects.length, dynamicCount);

          const appliedModNames = power.modifiers.map((m) => {
            const md = modifierDefs.find((d) => d.id === m.modifierId);
            return md ? md.name : m.modifierId;
          });

          return (
            <div key={power.id} className="power-card-item">
              <div className="power-card-top">
                <div className="power-card-icon">
                  <Zap size={18} />
                </div>
                <div className="power-card-info">
                  <span className="power-card-name">{power.name || t('powers.unnamed')}</span>
                  <span className="power-card-effect">{effectDef?.name || power.effectId} {power.ranks}</span>
                </div>
                <span className="power-card-cost">{totalCost} {t('common.pp')}</span>
              </div>

              {appliedModNames.length > 0 && (
                <div className="power-card-mods">
                  {appliedModNames.map((name, j) => (
                    <span key={j} className="power-mod-tag">{name}</span>
                  ))}
                </div>
              )}

              {power.alternateEffects.length > 0 && (
                <div className="power-alt-info">
                  <span>­ƒöÇ {power.alternateEffects.length} {t('powers.alternateEffects')}</span>
                </div>
              )}

              {power.notes && (
                <p className="power-card-notes">{power.notes}</p>
              )}

              <div className="power-card-actions">
                <Tooltip content={t('powers.editTooltip')}>
                  <button onClick={() => openEdit(i)} className="power-action-btn">
                    <Edit3 size={14} /> {t('common.edit')}
                  </button>
                </Tooltip>
                <button onClick={() => handleDeletePower(i)} className="power-action-btn power-action-btn--danger" title={t('common.remove')}>
                  <Trash2 size={14} />
                </button>
              </div>
            </div>
          );
        })}
      </div>

      <button className="power-new-btn" onClick={openNew}>
        <Plus size={18} /> {t('powers.newPowerBtn')}
      </button>

      {builderOpen && (
        <PowerBuilderOverlay
          existingPower={editIndex !== null ? powers[editIndex] : undefined}
          onSave={handleSavePower}
          onClose={() => { setBuilderOpen(false); setEditIndex(null); }}
        />
      )}

      <style>{`
        .power-empty { color: var(--c-text-muted); font-size: 0.85rem; font-style: italic; }
        .powers-grid { display: flex; flex-direction: column; gap: var(--s-sm); }

        .power-card-item {
          background: var(--c-surface-elevated); border: 1px solid var(--c-border);
          border-radius: var(--r-md); padding: var(--s-md);
          transition: border-color var(--t-fast), box-shadow var(--t-fast);
        }
        .power-card-item:hover {
          border-color: var(--c-border-active);
          box-shadow: 0 0 12px rgba(var(--c-primary-rgb), 0.15);
        }
        .power-card-top { display: flex; align-items: center; gap: var(--s-sm); }
        .power-card-icon {
          width: 36px; height: 36px; display: flex; align-items: center; justify-content: center;
          background: var(--c-primary-muted); border-radius: var(--r-sm); color: var(--c-primary);
        }
        .power-card-info { flex: 1; display: flex; flex-direction: column; }
        .power-card-name { font-weight: 700; font-size: 0.95rem; }
        .power-card-effect { font-size: 0.78rem; color: var(--c-text-secondary); }
        .power-card-cost { font-weight: 800; font-size: 1.1rem; color: var(--c-primary); font-variant-numeric: tabular-nums; }

        .power-card-mods { display: flex; flex-wrap: wrap; gap: 4px; margin-top: var(--s-sm); }
        .power-mod-tag {
          font-size: 0.7rem; padding: 2px 8px; border-radius: var(--r-full);
          background: var(--c-primary-muted); color: var(--c-primary); font-weight: 500;
        }
        .power-alt-info { font-size: 0.78rem; color: var(--c-accent); margin-top: var(--s-xs); }
        .power-card-notes { font-size: 0.78rem; color: var(--c-text-muted); font-style: italic; margin-top: var(--s-xs); }

        .power-card-actions {
          display: flex; gap: var(--s-xs); margin-top: var(--s-sm);
          padding-top: var(--s-sm); border-top: 1px solid var(--c-border);
        }
        .power-action-btn {
          display: flex; align-items: center; gap: 4px;
          background: transparent; border: 1px solid var(--c-border);
          border-radius: var(--r-sm); padding: 4px 10px;
          color: var(--c-text-secondary); font-family: var(--f-body);
          font-size: 0.75rem; cursor: pointer; transition: all var(--t-fast);
        }
        .power-action-btn:hover { background: var(--c-primary-muted); color: var(--c-primary); border-color: var(--c-primary); }
        .power-action-btn--danger:hover { background: rgba(248,113,113,0.15); color: var(--c-error); border-color: var(--c-error); }

        .power-new-btn {
          display: flex; align-items: center; justify-content: center; gap: var(--s-sm);
          margin-top: var(--s-sm); padding: var(--s-md);
          background: var(--c-primary-muted); border: 2px dashed var(--c-primary);
          border-radius: var(--r-md); color: var(--c-primary);
          font-family: var(--f-heading); font-size: 0.95rem; font-weight: 700;
          cursor: pointer; transition: all var(--t-fast); width: 100%;
        }
        .power-new-btn:hover { background: var(--c-primary); color: var(--c-text-inverse); box-shadow: var(--shadow-glow); }
      `}</style>
    </section>
  );
}

import { useState } from 'react';
import { useCharStore } from '../../store/charStore';
import type { ICharacterSkill, AbilityKey } from '../../entities/types';
import skillDefsRaw from '../../data/skills.json';
import { useLocalizedData } from '../../shared/hooks/useLocalizedData';
import { Tooltip } from '../../shared/ui/Tooltip';
import { Plus, Trash2 } from 'lucide-react';
import { useTranslation } from 'react-i18next';

export function SkillsPanel({ cost }: { cost: number }) {
  const { t } = useTranslation();
  const skillDefs = useLocalizedData(skillDefsRaw as any) as typeof skillDefsRaw;
  const skills = useCharStore((s) => s.character.skills);
  const abilities = useCharStore((s) => s.character.abilities);
  const [showAdd, setShowAdd] = useState(false);
  const [newSkillId, setNewSkillId] = useState('');
  const [newSubtype, setNewSubtype] = useState('');

  function setSkills(newSkills: ICharacterSkill[]) {
    useCharStore.setState((s) => ({
      character: { ...s.character, skills: newSkills },
      isDirty: true,
    }));
  }

  function addSkill() {
    if (!newSkillId) return;
    const def = skillDefs.find((s) => s.id === newSkillId);
    if (!def) return;

    const entry: ICharacterSkill = {
      skillId: newSkillId,
      ranks: 1,
      subtype: def.subtyped ? (newSubtype || 'Geral') : null,
    };
    setSkills([...skills, entry]);
    setNewSkillId('');
    setNewSubtype('');
    setShowAdd(false);
  }

  function updateRanks(index: number, ranks: number) {
    const next = [...skills];
    next[index] = { ...next[index], ranks: Math.max(0, ranks) };
    setSkills(next);
  }

  function removeSkill(index: number) {
    setSkills(skills.filter((_, i) => i !== index));
  }

  const totalRanks = skills.reduce((sum, s) => sum + s.ranks, 0);

  // Available skills to add (non-subtyped only show once if not already added)
  const availableToAdd = skillDefs.filter((def) => {
    if (def.subtyped) return true; // can add multiple subtypes
    return !skills.some((s) => s.skillId === def.id);
  });

  return (
    <section className="panel">
      <div className="panel-header">
        <h2 className="panel-title">{t('skills.title')}</h2>
        <span className="panel-cost">{cost} {t('common.pp')} <span className="skill-ranks-counter">({totalRanks} {totalRanks === 1 ? t('common.rank') : t('common.ranks')})</span></span>
      </div>

      {skills.length === 0 && (
        <p className="skill-empty">{t('skills.noSkills')}</p>
      )}

      <div className="skills-list">
        {skills.map((skill, i) => {
          const def = skillDefs.find((d) => d.id === skill.skillId);
          if (!def) return null;
          const abilityVal = abilities[def.baseAbility as AbilityKey] || 0;
          const total = abilityVal + skill.ranks;
          const displayName = def.subtyped ? `${def.name}: ${skill.subtype}` : def.name;

          return (
            <div key={`${skill.skillId}-${skill.subtype}-${i}`} className="skill-row">
              <Tooltip content={`Base: ${def.baseAbility.toUpperCase()} (${abilityVal}) + ${t('common.ranks').replace(/^./, (c)=>c.toUpperCase())}`}>
                <span className="skill-name">{displayName}</span>
              </Tooltip>
              <span className="skill-base">{def.baseAbility.toUpperCase()} {abilityVal}</span>
              <span className="skill-plus">+</span>
              <input
                type="number"
                min={0}
                className="skill-input"
                value={skill.ranks}
                onChange={(e) => updateRanks(i, Number(e.target.value) || 0)}
              />
              <span className="skill-total">= {total}</span>
              <button className="skill-remove" onClick={() => removeSkill(i)} title={t('common.remove')}>
                <Trash2 size={14} />
              </button>
            </div>
          );
        })}
      </div>

      {/* Add Skill */}
      {!showAdd ? (
        <button className="skill-add-btn" onClick={() => setShowAdd(true)}>
          <Plus size={16} /> {t('skills.addSkill')}
        </button>
      ) : (
        <div className="skill-add-form">
          <select value={newSkillId} onChange={(e) => setNewSkillId(e.target.value)} className="skill-select">
            <option value="">{t('common.select')}</option>
            {availableToAdd.map((d) => (
              <option key={d.id} value={d.id}>{d.name}</option>
            ))}
          </select>
          {newSkillId && skillDefs.find((d) => d.id === newSkillId)?.subtyped && (
            <input
              className="skill-subtype-input"
              value={newSubtype}
              onChange={(e) => setNewSubtype(e.target.value)}
              placeholder={t('skills.subtypePlaceholder')}
            />
          )}
          <button className="skill-confirm-btn" onClick={addSkill} disabled={!newSkillId}>
            {t('common.add')}
          </button>
          <button className="skill-cancel-btn" onClick={() => { setShowAdd(false); setNewSkillId(''); }}>
            {t('common.cancel')}
          </button>
        </div>
      )}

      <style>{`
        .skill-ranks-counter { font-size: 0.75rem; color: var(--c-text-muted); font-weight: 400; }
        .skill-empty { color: var(--c-text-muted); font-size: 0.85rem; font-style: italic; }
        .skills-list { display: flex; flex-direction: column; gap: var(--s-xs); }
        .skill-row {
          display: flex; align-items: center; gap: var(--s-sm);
          background: var(--c-surface-elevated); border: 1px solid var(--c-border);
          border-radius: var(--r-sm); padding: var(--s-xs) var(--s-md);
          transition: border-color var(--t-fast);
        }
        .skill-row:hover { border-color: var(--c-border-active); }
        .skill-name { font-weight: 500; font-size: 0.85rem; min-width: 180px; cursor: help; }
        .skill-base { font-size: 0.78rem; color: var(--c-text-secondary); min-width: 60px; }
        .skill-plus { color: var(--c-text-muted); font-size: 0.85rem; }
        .skill-input {
          width: 50px; text-align: center;
          background: var(--c-bg); border: 1px solid var(--c-border);
          border-radius: var(--r-sm); color: var(--c-text);
          font-family: var(--f-body); font-size: 0.9rem; padding: var(--s-xs);
        }
        .skill-input:focus { outline: none; border-color: var(--c-primary); }
        .skill-total { font-weight: 700; font-size: 0.9rem; color: var(--c-primary); min-width: 35px; text-align: right; }
        .skill-remove {
          background: transparent; border: none; color: var(--c-text-muted);
          cursor: pointer; opacity: 0; transition: opacity var(--t-fast), color var(--t-fast);
          padding: var(--s-xs); border-radius: var(--r-sm); display: flex;
        }
        .skill-row:hover .skill-remove { opacity: 1; }
        .skill-remove:hover { color: var(--c-error); }

        .skill-add-btn {
          display: flex; align-items: center; gap: var(--s-xs);
          margin-top: var(--s-sm); padding: var(--s-sm) var(--s-md);
          background: transparent; border: 1px dashed var(--c-border);
          border-radius: var(--r-sm); color: var(--c-text-secondary);
          font-family: var(--f-body); font-size: 0.82rem; cursor: pointer;
          transition: all var(--t-fast); width: 100%;
          justify-content: center;
        }
        .skill-add-btn:hover { border-color: var(--c-primary); color: var(--c-primary); background: var(--c-primary-muted); }

        .skill-add-form {
          display: flex; gap: var(--s-sm); align-items: center;
          margin-top: var(--s-sm); flex-wrap: wrap;
        }
        .skill-select, .skill-subtype-input {
          background: var(--c-surface-elevated); border: 1px solid var(--c-border);
          border-radius: var(--r-sm); padding: var(--s-sm) var(--s-md);
          color: var(--c-text); font-family: var(--f-body); font-size: 0.85rem;
        }
        .skill-select { min-width: 180px; }
        .skill-subtype-input { min-width: 140px; }
        .skill-select:focus, .skill-subtype-input:focus { outline: none; border-color: var(--c-primary); }
        .skill-confirm-btn, .skill-cancel-btn {
          padding: var(--s-xs) var(--s-md); border-radius: var(--r-sm);
          font-family: var(--f-body); font-size: 0.82rem; cursor: pointer;
          border: 1px solid var(--c-border);
        }
        .skill-confirm-btn { background: var(--c-primary); color: var(--c-text-inverse); border-color: var(--c-primary); }
        .skill-confirm-btn:disabled { opacity: 0.4; cursor: not-allowed; }
        .skill-cancel-btn { background: transparent; color: var(--c-text-secondary); }
      `}</style>
    </section>
  );
}

import { useState, useRef, useEffect } from 'react';

import { useAppStore } from '../../store/appStore';
import { useCharStore } from '../../store/charStore';
import { useCalculatedPP } from '../hooks/useCalculatedPP';
import { exportCharacterJSON, importCharacterJSON } from '../../services/fileService';
import { Settings, Download, Upload, FilePlus, Sun, Moon, Shield, ShieldOff } from 'lucide-react';

const THEMES = [
  { id: 'dark-knight', label: 'Dark Knight' },
  { id: 'arc-reactor', label: 'Arc Reactor' },
  { id: 'cyberpunk', label: 'Cyberpunk' },
  { id: 'light-print', label: 'Light Print' },
];
import { useTranslation } from 'react-i18next';
import { Globe } from 'lucide-react';

const LANGUAGES = [
  { id: 'en', label: 'English' },
  { id: 'pt-BR', label: 'Portugu├¬s (BR)' },
];

export function MenuBar() {
  const { t, i18n } = useTranslation();
  const { theme, setTheme, language, setLanguage } = useAppStore((s) => ({
    theme: s.theme, setTheme: s.setTheme,
    language: s.language, setLanguage: s.setLanguage
  }));

  // ensure i18n is synced with store on mount
  useEffect(() => {
    if (i18n.language !== language) {
      i18n.changeLanguage(language);
    }
  }, [language, i18n]);

  const strictMode = useAppStore((s) => s.strictMode);
  const toggleStrictMode = useAppStore((s) => s.toggleStrictMode);
  const character = useCharStore((s) => s.character);
  const loadCharacter = useCharStore((s) => s.loadCharacter);
  const resetCharacter = useCharStore((s) => s.resetCharacter);
  const { totalSpent, totalAvailable, remaining } = useCalculatedPP();

  const [settingsOpen, setSettingsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Close dropdown on outside click
  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setSettingsOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  async function handleImport(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
      const char = await importCharacterJSON(file);
      loadCharacter(char);
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Error importing file.');
    }
    e.target.value = '';
  }

  function handleLanguageChange(lang: string) {
    setLanguage(lang);
    i18n.changeLanguage(lang);
  }

  return (
    <header className="menubar">
      <div className="menubar-left">
        <h1 className="menubar-title">{t('app.title')}</h1>
        <span className="menubar-pp" data-over={remaining < 0}>
          <strong>{totalSpent}</strong> / {totalAvailable} {t('common.pp')}
          {remaining < 0 && <span className="menubar-pp-warning"> ({remaining})</span>}
        </span>
      </div>

      <nav className="menubar-actions">
        <button className="menubar-btn" onClick={resetCharacter} title={t('menu.new')}>
          <FilePlus size={18} /> <span>{t('menu.new')}</span>
        </button>
        <button className="menubar-btn" onClick={() => exportCharacterJSON(character, i18n.language)} title={t('menu.export')}>
          <Download size={18} /> <span>{t('menu.export')}</span>
        </button>
        <button className="menubar-btn" onClick={() => fileInputRef.current?.click()} title={t('menu.import')}>
          <Upload size={18} /> <span>{t('menu.import')}</span>
        </button>
        <input
          ref={fileInputRef}
          type="file"
          accept=".json"
          onChange={handleImport}
          style={{ display: 'none' }}
        />

        {/* Settings Dropdown */}
        <div className="menubar-dropdown-wrapper" ref={dropdownRef}>
          <button
            className="menubar-btn"
            onClick={() => setSettingsOpen(!settingsOpen)}
            title={t('menu.settings')}
          >
            <Settings size={18} />
          </button>

          {settingsOpen && (
            <div className="menubar-dropdown">
              <div className="dropdown-section">
                <span className="dropdown-label">{t('menu.theme')}</span>
                {THEMES.map((tItem) => (
                  <button
                    key={tItem.id}
                    className={`dropdown-item ${theme === tItem.id ? 'active' : ''}`}
                    onClick={() => setTheme(tItem.id as any)}
                  >
                    {tItem.id.includes('light') ? <Sun size={14} /> : <Moon size={14} />}
                    {tItem.label}
                  </button>
                ))}
              </div>
              <div className="dropdown-divider" />
              <div className="dropdown-section">
                <span className="dropdown-label">{t('menu.strictMode')}</span>
                <button className="dropdown-item" onClick={toggleStrictMode}>
                  {strictMode ? <Shield size={14} /> : <ShieldOff size={14} />}
                  {t('menu.strictMode')}: <strong>{strictMode ? t('menu.strictMode.active') : t('menu.strictMode.disabled')}</strong>
                </button>
              </div>
              <div className="dropdown-divider" />
              <div className="dropdown-section">
                <span className="dropdown-label">{t('menu.language')}</span>
                {LANGUAGES.map((l) => (
                  <button
                    key={l.id}
                    className={`dropdown-item ${language === l.id ? 'active' : ''}`}
                    onClick={() => handleLanguageChange(l.id)}
                  >
                    <Globe size={14} />
                    {l.label}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </nav>

      <style>{`
        .menubar {
          display: flex;
          align-items: center;
          justify-content: space-between;
          padding: var(--s-sm) var(--s-lg);
          background: var(--c-surface);
          border-bottom: 1px solid var(--c-border);
          position: sticky;
          top: 0;
          z-index: 100;
          backdrop-filter: blur(12px);
        }
        .menubar-left {
          display: flex;
          align-items: center;
          gap: var(--s-lg);
        }
        .menubar-title {
          font-family: var(--f-heading);
          font-size: 1.1rem;
          font-weight: 800;
          background: linear-gradient(135deg, var(--c-primary), var(--c-accent));
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }
        .menubar-pp {
          font-size: 0.85rem;
          color: var(--c-text-secondary);
          font-variant-numeric: tabular-nums;
        }
        .menubar-pp[data-over="true"] {
          color: var(--c-error);
        }
        .menubar-pp-warning {
          color: var(--c-error);
          font-weight: 600;
        }
        .menubar-actions {
          display: flex;
          align-items: center;
          gap: var(--s-xs);
        }
        .menubar-btn {
          display: flex;
          align-items: center;
          gap: var(--s-xs);
          padding: var(--s-xs) var(--s-sm);
          background: transparent;
          border: 1px solid transparent;
          border-radius: var(--r-md);
          color: var(--c-text-secondary);
          font-family: var(--f-body);
          font-size: 0.8rem;
          cursor: pointer;
          transition: all var(--t-fast);
        }
        .menubar-btn:hover {
          background: var(--c-primary-muted);
          color: var(--c-text);
          border-color: var(--c-border);
        }
        .menubar-dropdown-wrapper {
          position: relative;
        }
        .menubar-dropdown {
          position: absolute;
          right: 0;
          top: calc(100% + var(--s-xs));
          min-width: 220px;
          background: var(--c-surface-elevated);
          border: 1px solid var(--c-border);
          border-radius: var(--r-md);
          box-shadow: var(--shadow-lg);
          padding: var(--s-sm);
          animation: fadeIn 0.15s ease;
          z-index: 200;
        }
        .dropdown-section {
          display: flex;
          flex-direction: column;
          gap: 2px;
        }
        .dropdown-label {
          font-size: 0.7rem;
          font-weight: 600;
          text-transform: uppercase;
          letter-spacing: 0.05em;
          color: var(--c-text-muted);
          padding: var(--s-xs) var(--s-sm);
        }
        .dropdown-item {
          display: flex;
          align-items: center;
          gap: var(--s-sm);
          padding: var(--s-xs) var(--s-sm);
          background: transparent;
          border: none;
          border-radius: var(--r-sm);
          color: var(--c-text);
          font-family: var(--f-body);
          font-size: 0.82rem;
          cursor: pointer;
          transition: background var(--t-fast);
          width: 100%;
          text-align: left;
        }
        .dropdown-item:hover {
          background: var(--c-primary-muted);
        }
        .dropdown-item.active {
          background: var(--c-primary-muted);
          color: var(--c-primary);
          font-weight: 600;
        }
        .dropdown-divider {
          height: 1px;
          background: var(--c-border);
          margin: var(--s-sm) 0;
        }
      `}</style>
    </header>
  );
}
